[RISCV-SPEC] 11.1.8. Supporting Sail Code
This section contains the supporting Sail code referenced by the instruction descriptions throughout the specification. The Sail Manual is recommended reading in order to best understand the supporting code.

/* Auxiliary function for performing GF multiplication */ val xt2 : bits ( 8 ) -> bits ( 8 ) function xt2 (x) = { (x << 1 ) ^ ( if bit_to_bool(x[ 7 ]) then 0x1b else 0x00 ) } val xt3 : bits ( 8 ) -> bits ( 8 )

function xt3 (x) = x ^ xt2(x) /* Multiply 8-bit field element by 4-bit value for AES MixCols step */ val gfmul : ( bits ( 8 ), bits ( 4 )) -> bits ( 8 ) function gfmul ( x, y) = { ( if bit_to_bool(y[ 0 ]) then x else 0x00 ) ^ ( if bit_to_bool(y[ 1 ]) then xt2(        x) else 0x00 ) ^ ( if bit_to_bool(y[ 2 ]) then xt2(xt2(    x)) else 0x00 ) ^ ( if bit_to_bool(y[ 3 ]) then xt2(xt2(xt2(x))) else 0x00 ) } /* 8-bit to 32-bit partial AES Mix Column - forwards */ val aes_mixcolumn_byte_fwd : bits ( 8 ) -> bits ( 32 ) function aes_mixcolumn_byte_fwd (so) = { gfmul(so, 0x3 ) @ so @ so @ gfmul(so, 0x2 ) } /* 8-bit to 32-bit partial AES Mix Column - inverse*/ val aes_mixcolumn_byte_inv : bits ( 8 ) -> bits ( 32 ) function aes_mixcolumn_byte_inv (so) = { gfmul(so, 0xb ) @ gfmul(so, 0xd ) @ gfmul(so, 0x9 ) @ gfmul(so, 0xe ) } /* 32-bit to 32-bit AES forward MixColumn */ val aes_mixcolumn_fwd : bits ( 32 ) -> bits ( 32 ) function aes_mixcolumn_fwd (x) = { let s0 : bits ( 8 ) = x[ 7 .. 0 ]; let s1 : bits ( 8 ) = x[ 15 .. 8 ]; let s2 : bits ( 8 ) = x[ 23 .. 16 ]; let s3 : bits ( 8 ) = x[ 31 .. 24 ]; let b0 : bits ( 8 ) = xt2(s0) ^ xt3(s1) ^    (s2) ^    (s3); let b1 : bits ( 8 ) =    (s0) ^ xt2(s1) ^ xt3(s2) ^    (s3); let b2 : bits ( 8 ) =    (s0) ^    (s1) ^ xt2(s2) ^ xt3(s3); let b3 : bits ( 8 ) = xt3(s0) ^    (s1) ^    (s2) ^ xt2(s3); b3 @ b2 @ b1 @ b0 /* Return value */ } /* 32-bit to 32-bit AES inverse MixColumn */ val aes_mixcolumn_inv : bits ( 32 ) -> bits ( 32 ) function aes_mixcolumn_inv (x) = { let s0 : bits ( 8 ) = x[ 7 .. 0 ]; let s1 : bits ( 8 ) = x[ 15 .. 8 ]; let s2 : bits ( 8 ) = x[ 23 .. 16 ]; let s3 : bits ( 8 ) = x[ 31 .. 24 ]; let b0 : bits ( 8 ) = gfmul(s0, 0xE ) ^ gfmul(s1, 0xB ) ^ gfmul(s2, 0xD ) ^ gfmul (s3, 0x9 ); let b1 : bits ( 8 ) = gfmul(s0, 0x9 ) ^ gfmul(s1, 0xE ) ^ gfmul(s2, 0xB ) ^ gfmul (s3, 0xD ); let b2 : bits ( 8 ) = gfmul(s0, 0xD ) ^ gfmul(s1, 0x9 ) ^ gfmul(s2, 0xE ) ^ gfmul (s3, 0xB );

