/* Lookup function - takes an index and a table, and retrieves the * x'th element of that table. Note that the Sail vector literals * start at index 255, and go down to 0. */ val sbox_lookup : ( bits ( 8 ), vector( 256 , bits ( 8 ))) -> bits ( 8 ) function sbox_lookup (x, table) = { table[ 255 - unsigned(x)] } /* Easy function to perform a forward AES SBox operation on 1 byte. */ val aes_sbox_fwd : bits ( 8 ) -> bits ( 8 ) function aes_sbox_fwd (x) = sbox_lookup(x, aes_sbox_fwd_table) /* Easy function to perform an inverse AES SBox operation on 1 byte. */ val aes_sbox_inv : bits ( 8 ) -> bits ( 8 ) function aes_sbox_inv (x) = sbox_lookup(x, aes_sbox_inv_table) /* AES SubWord function used in the key expansion * - Applies the forward sbox to each byte in the input word. */ val aes_subword_fwd : bits ( 32 ) -> bits ( 32 ) function aes_subword_fwd (x) = { aes_sbox_fwd(x[ 31 .. 24 ]) @ aes_sbox_fwd(x[ 23 .. 16 ]) @ aes_sbox_fwd(x[ 15 .. 8 ]) @ aes_sbox_fwd(x[ 7 .. 0 ]) } /* AES Inverse SubWord function. * - Applies the inverse sbox to each byte in the input word. */ val aes_subword_inv : bits ( 32 ) -> bits ( 32 ) function aes_subword_inv (x) = { aes_sbox_inv(x[ 31 .. 24 ]) @ aes_sbox_inv(x[ 23 .. 16 ]) @ aes_sbox_inv(x[ 15 .. 8 ]) @ aes_sbox_inv(x[ 7 .. 0 ]) } /* Easy function to perform an SM4 SBox operation on 1 byte. */ val sm4_sbox : bits ( 8 ) -> bits ( 8 ) function sm4_sbox (x) = sbox_lookup(x, sm4_sbox_table) val aes_get_column : ( bits ( 128 ), nat) -> bits ( 32 ) function aes_get_column (state,c) = (state >> (to_bits( 7 , 32 * c)))[ 31 .. 0 ] /* 64-bit to 64-bit function which applies the AES forward sbox to each byte * in a 64-bit word. */ val aes_apply_fwd_sbox_to_each_byte : bits ( 64 ) -> bits ( 64 )

function aes_apply_fwd_sbox_to_each_byte (x) = { aes_sbox_fwd(x[ 63 .. 56 ]) @ aes_sbox_fwd(x[ 55 .. 48 ]) @ aes_sbox_fwd(x[ 47 .. 40 ]) @ aes_sbox_fwd(x[ 39 .. 32 ]) @ aes_sbox_fwd(x[ 31 .. 24 ]) @ aes_sbox_fwd(x[ 23 .. 16 ]) @ aes_sbox_fwd(x[ 15 .. 8 ]) @ aes_sbox_fwd(x[ 7 .. 0 ]) } /* 64-bit to 64-bit function which applies the AES inverse sbox to each byte * in a 64-bit word. */ val aes_apply_inv_sbox_to_each_byte : bits ( 64 ) -> bits ( 64 ) function aes_apply_inv_sbox_to_each_byte (x) = { aes_sbox_inv(x[ 63 .. 56 ]) @ aes_sbox_inv(x[ 55 .. 48 ]) @ aes_sbox_inv(x[ 47 .. 40 ]) @ aes_sbox_inv(x[ 39 .. 32 ]) @ aes_sbox_inv(x[ 31 .. 24 ]) @ aes_sbox_inv(x[ 23 .. 16 ]) @ aes_sbox_inv(x[ 15 .. 8 ]) @ aes_sbox_inv(x[ 7 .. 0 ]) } /* * AES full-round transformation functions.

